import html2canvas from "html2canvas";
import jsPDF from "jspdf";

import type { CotizacionWorkflowRecord } from "@/types/cotizacion-workflow";

function sanitizeFileNamePart(value: string) {
  return value
    .trim()
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-+|-+$/g, "")
    .slice(0, 50);
}

export function buildCotizacionPdfFileName(record: CotizacionWorkflowRecord) {
  const obra = sanitizeFileNamePart(record.obra) || "proyecto";
  return `${record.codigo.toLowerCase()}-${obra}.pdf`;
}

type ExportCotizacionPdfInput = {
  element: HTMLElement;
  fileName: string;
};

export async function exportCotizacionElementToPdf({
  element,
  fileName,
}: ExportCotizacionPdfInput) {
  const canvas = await html2canvas(element, {
    backgroundColor: "#ffffff",
    scale: Math.max(2, Math.min(window.devicePixelRatio || 1, 3)),
    useCORS: true,
    logging: false,
    windowWidth: element.scrollWidth,
    width: element.scrollWidth,
    height: element.scrollHeight,
  });

  const pdf = new jsPDF({
    orientation: "portrait",
    unit: "mm",
    format: "a4",
    compress: true,
  });

  const pageWidth = pdf.internal.pageSize.getWidth();
  const pageHeight = pdf.internal.pageSize.getHeight();
  const margin = 8;
  const printableWidth = pageWidth - margin * 2;
  const printableHeight = pageHeight - margin * 2;
  const pxPerMm = canvas.width / printableWidth;
  const pageCanvasHeight = Math.max(1, Math.floor(printableHeight * pxPerMm));

  let offsetY = 0;
  let pageIndex = 0;

  while (offsetY < canvas.height) {
    const currentSliceHeight = Math.min(pageCanvasHeight, canvas.height - offsetY);
    const pageCanvas = document.createElement("canvas");
    pageCanvas.width = canvas.width;
    pageCanvas.height = currentSliceHeight;

    const context = pageCanvas.getContext("2d");

    if (!context) {
      throw new Error("No se pudo preparar el canvas para exportar el PDF");
    }

    context.fillStyle = "#ffffff";
    context.fillRect(0, 0, pageCanvas.width, pageCanvas.height);
    context.drawImage(
      canvas,
      0,
      offsetY,
      canvas.width,
      currentSliceHeight,
      0,
      0,
      canvas.width,
      currentSliceHeight
    );

    const imageData = pageCanvas.toDataURL("image/jpeg", 0.96);
    const sliceHeightMm = currentSliceHeight / pxPerMm;

    if (pageIndex > 0) {
      pdf.addPage();
    }

    pdf.addImage(imageData, "JPEG", margin, margin, printableWidth, sliceHeightMm, undefined, "FAST");

    offsetY += currentSliceHeight;
    pageIndex += 1;
  }

  const blob = pdf.output("blob");
  const file = new File([blob], fileName, { type: "application/pdf" });

  return { blob, file };
}

export function downloadPdfBlob(blob: Blob, fileName: string) {
  const objectUrl = window.URL.createObjectURL(blob);
  const link = document.createElement("a");

  link.href = objectUrl;
  link.download = fileName;
  document.body.append(link);
  link.click();
  link.remove();

  window.setTimeout(() => {
    window.URL.revokeObjectURL(objectUrl);
  }, 1000);
}

export function canSharePdfFile(file: File) {
  if (typeof navigator === "undefined" || typeof navigator.share !== "function") {
    return false;
  }

  if (typeof navigator.canShare !== "function") {
    return false;
  }

  return navigator.canShare({ files: [file] });
}

type ShareCotizacionPdfInput = {
  file: File;
  title: string;
  text: string;
};

export async function shareCotizacionPdf({
  file,
  title,
  text,
}: ShareCotizacionPdfInput) {
  if (!canSharePdfFile(file)) {
    return false;
  }

  await navigator.share({
    title,
    text,
    files: [file],
  });

  return true;
}
